mapper.sql:
where d.tenant_id = #{tenantId}

    and (lower(d.metric_code) like concat('%', lower(#{keyword}), '%')
     or lower(d.metric_name) like concat('%', lower(#{keyword}), '%'))

and d.metric_category = #{metricCategory}
and d.object_type = #{objectType}
and d.enabled = #{enabled}

mapper.select:
select d.*,
       (select count(1) from fp_metric_implementation i where i.tenant_id = d.tenant_id and i.metric_definition_id = d.id) as implementation_count
from fp_metric_definition d where d.tenant_id = #{tenantId} and d.id = #{id}

select d.*,
       (select count(1) from fp_metric_implementation i where i.tenant_id = d.tenant_id and i.metric_definition_id = d.id) as implementation_count
from fp_metric_definition d where d.tenant_id = #{tenantId} and d.metric_code = #{metricCode}

mapper.update:
update fp_metric_definition
set metric_code = #{metricCode}, metric_name = #{metricName}, metric_category = #{metricCategory},
    object_type = #{objectType}, value_unit = #{valueUnit}, value_precision = #{valuePrecision},
    mapping_json = #{mappingJson}, enabled = #{enabled}, description = #{description}, updated_at = #{updatedAt}
where tenant_id = #{tenantId} and id = #{id}
